const R2_ACCESS_KEY_ID = '1ad7377299c9a4474623eb49b3cb2201';
const R2_SECRET_ACCESS_KEY = '9122a1da40ebdca3d96ba16d7733981d246a71a635c5587a78e6a584b6c38fed';
const R2_ENDPOINT_HOST = '0b487c633839b7b611c2d68f1ba5e8c9.r2.cloudflarestorage.com';
const R2_BUCKET = 'my-videos';
const AWS_REGION = 'auto';
const PUT_EXPIRES = 3600;
const GET_EXPIRES = 604800;

const prev = $input.first().json;
const videoId = prev.selected?.pexelsVideoId || 'unknown';
const r2Key = 'found material/' + videoId + '.mp4';  // НОВАЯ ПАПКА!
const canonicalUri = '/' + R2_BUCKET + '/' + r2Key;

const crypto = require('crypto');

function hmacSha256(key, data) {
  return crypto.createHmac('sha256', key).update(data).digest();
}

function sha256(data) {
  return crypto.createHash('sha256').update(data).digest('hex');
}

function generatePresignedUrl(method, expiresIn) {
  const now = new Date();
  const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '').substring(0, 15) + 'Z';
  const dateStamp = amzDate.substring(0, 8);
  const credentialScope = `${dateStamp}/${AWS_REGION}/s3/aws4_request`;

  const queryParams = {
    'X-Amz-Algorithm': 'AWS4-HMAC-SHA256',
    'X-Amz-Credential': `${R2_ACCESS_KEY_ID}/${credentialScope}`,
    'X-Amz-Date': amzDate,
    'X-Amz-Expires': expiresIn.toString(),
    'X-Amz-SignedHeaders': 'host'
  };

  const sortedKeys = Object.keys(queryParams).sort();
  const canonicalQueryString = sortedKeys.map(k => `${encodeURIComponent(k)}=${encodeURIComponent(queryParams[k])}`).join('&');
  const canonicalHeaders = `host:${R2_ENDPOINT_HOST}\n`;
  const signedHeaders = 'host';
  const payloadHash = 'UNSIGNED-PAYLOAD';
  const canonicalRequest = `${method}\n${canonicalUri}\n${canonicalQueryString}\n${canonicalHeaders}\n${signedHeaders}\n${payloadHash}`;

  const stringToSign = `AWS4-HMAC-SHA256\n${amzDate}\n${credentialScope}\n${sha256(canonicalRequest)}`;

  const kDate = hmacSha256('AWS4' + R2_SECRET_ACCESS_KEY, dateStamp);
  const kRegion = hmacSha256(kDate, AWS_REGION);
  const kService = hmacSha256(kRegion, 's3');
  const kSigning = hmacSha256(kService, 'aws4_request');
  const signature = crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');

  return `https://${R2_ENDPOINT_HOST}${canonicalUri}?${canonicalQueryString}&X-Amz-Signature=${signature}`;
}

return {
  ...prev,
  r2Key,
  presigned_put_url: generatePresignedUrl('PUT', PUT_EXPIRES),
  presigned_get_url: generatePresignedUrl('GET', GET_EXPIRES)
};

const presign = $('Подпись R2 (PUT/GET)').first().json;

return [{ json: {
  chat_id: presign.chat_id,
  query: presign.query,
  query_ru: presign.query_ru,
  selected: presign.selected,
  r2_key: presign.r2_key,
  public_url: presign.public_url,
  ai_score: presign.ai_score || 0,
  ai_reason: presign.ai_reason || '',
  ai_sees: presign.ai_sees || '',
  success: true
} }];

