const resp = $input.first().json;
const extractData = $('Определить маршрут').first().json;
let analysis = {project_key: 'other', topic_query: '', filters: {min_duration_sec: 10, max_duration_sec: 120}};
try {
  const txt = resp.content?.parts?.[0]?.text || resp.text || JSON.stringify(resp);
  const m = txt.match(/\{[\s\S]*\}/);
  if (m) analysis = JSON.parse(m[0]);
} catch(e) {}
analysis.project_key = analysis.project_key || 'other';
analysis.topic_query = analysis.topic_query || 'gameplay';
return [{ json: { chat_id: extractData.chat_id, analysis: analysis } }];

const prev = $('Разобрать ответ Gemini').first().json;
const items = $input.first().json.items || [];
function parseDuration(iso) { const m = (iso || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?/); if (!m) return 0; return (parseInt(m[1]||0)*3600) + (parseInt(m[2]||0)*60) + parseInt(m[3]||0); }
const validVideos = items.filter(v => { const dur = parseDuration(v.contentDetails?.duration || ''); return dur >= 10 && dur <= 120; }).slice(0, 5).map((v, idx) => ({ videoId: v.id, title: v.snippet?.title || '', duration: parseDuration(v.contentDetails?.duration || ''), views: parseInt(v.statistics?.viewCount || 0), watch_url: 'https://www.youtube.com/watch?v=' + v.id, index: idx }));
return validVideos.map(video => ({ json: { chat_id: prev.chat_id, analysis: prev.analysis, video: video, total_videos: validVideos.length } }));

const R2_ACCESS_KEY_ID = '1ad7377299c9a4474623eb49b3cb2201';
const R2_SECRET_ACCESS_KEY = '9122a1da40ebdca3d96ba16d7733981d246a71a635c5587a78e6a584b6c38fed';
const R2_ENDPOINT_HOST = '0b487c633839b7b611c2d68f1ba5e8c9.r2.cloudflarestorage.com';
const R2_BUCKET = 'my-videos';
const AWS_REGION = 'auto';
const EXPIRES = 3600;
const prev = $input.first().json;
const r2Key = (prev.analysis?.project_key || 'other') + '/raw/youtube/' + (prev.video?.videoId || 'unknown') + '.mp4';
const now = new Date();
const amzDate = now.toISOString().replace(/[:-]|\.\d{3}/g, '').substring(0, 15) + 'Z';
const dateStamp = amzDate.substring(0, 8);
const canonicalUri = '/' + R2_BUCKET + '/' + r2Key;
const credentialScope = `${dateStamp}/${AWS_REGION}/s3/aws4_request`;
const credential = `${R2_ACCESS_KEY_ID}/${credentialScope}`;
const queryParams = { 'X-Amz-Algorithm': 'AWS4-HMAC-SHA256', 'X-Amz-Credential': credential, 'X-Amz-Date': amzDate, 'X-Amz-Expires': String(EXPIRES), 'X-Amz-SignedHeaders': 'host' };
const sortedKeys = Object.keys(queryParams).sort();
const canonicalQueryString = sortedKeys.map(k => encodeURIComponent(k) + '=' + encodeURIComponent(queryParams[k])).join('&');
const canonicalHeaders = 'host:' + R2_ENDPOINT_HOST + '\n';
const canonicalRequest = ['PUT', canonicalUri, canonicalQueryString, canonicalHeaders, 'host', 'UNSIGNED-PAYLOAD'].join('\n');
const crypto = require('crypto');
const canonicalRequestHash = crypto.createHash('sha256').update(canonicalRequest).digest('hex');
const stringToSign = ['AWS4-HMAC-SHA256', amzDate, credentialScope, canonicalRequestHash].join('\n');
function hmacSha256(key, data) { return crypto.createHmac('sha256', key).update(data).digest(); }
const kDate = hmacSha256('AWS4' + R2_SECRET_ACCESS_KEY, dateStamp);
const kRegion = hmacSha256(kDate, AWS_REGION);
const kService = hmacSha256(kRegion, 's3');
const kSigning = hmacSha256(kService, 'aws4_request');
const signature = crypto.createHmac('sha256', kSigning).update(stringToSign).digest('hex');
const putUrl = `https://${R2_ENDPOINT_HOST}${canonicalUri}?${canonicalQueryString}&X-Amz-Signature=${signature}`;
return [{ json: { ...prev, r2_key: r2Key, presigned_put_url: putUrl } }];

const input = $input.first().json;
const prev = $('Подпись R2 (YouTube)').first().json;
const results = Array.isArray(input) ? input : [input];
const actorResult = results[0] || {};
return [{ json: { chat_id: prev.chat_id, analysis: prev.analysis, video: prev.video, result: { videoId: prev.video?.videoId || 'unknown', title: prev.video?.title || 'untitled', r2_key: prev.r2_key, quality: actorResult.client || '480p', download_success: actorResult.ok === true, upload_success: actorResult.ok === true, file_size_mb: actorResult.sizeMB || null, error: actorResult.error || null } } }];

const items = $input.all();
if (!items.length) return [{ json: { error: 'No results', videos: [], success_count: 0, chat_id: '' } }];
const firstItem = items[0].json;
const results = items.map(i => i.json.result).filter(r => r);
const successCount = results.filter(r => r.upload_success).length;
return [{ json: { chat_id: firstItem.chat_id, project_key: firstItem.analysis.project_key, topic_query: firstItem.analysis.topic_query, bucket: 'my-videos', timestamp: new Date().toISOString(), summary: { total: results.length, success: successCount, failed: results.length - successCount }, videos: results } }];

const staticData = $getWorkflowStaticData('global');
const sessions = staticData.activeSessions || {};
const data = $input.first().json;
const hasCallback = !!data.callback_query;
const hasMessage = !!data.message;

if (hasCallback) {
  const cb = data.callback_query;
  const callbackData = cb.data || '';
  const parts = callbackData.split(':');
  const action = parts[0] || '';
  const requestId = parts[1] || '';

  return [{ json: {
    type: 'callback',
    chat_id: cb.message?.chat?.id || cb.from?.id,
    callback_id: cb.id,
    action: action,
    requestId: requestId,
    from: cb.from
  } }];
}

if (hasMessage) {
  const msg = data.message;
  const chatId = msg.chat?.id;
  const text = (msg.text || msg.caption || '').trim();
  const hasPhoto = !!(msg.photo && msg.photo.length > 0);
  let photoId = null;
  if (hasPhoto) {
    photoId = msg.photo[msg.photo.length - 1].file_id;
  }

  // Команды выхода из сессии
  if (text === '/exit' || text === '/cancel' || text === '/stop' || text === 'выход') {
    delete sessions[chatId];
    staticData.activeSessions = sessions;
    return [{ json: {
      type: 'exit_session',
      chat_id: chatId,
      from: msg.from
    } }];
  }

  // Проверка активной сессии с агентом
  const session = sessions[chatId];
  if (session && session.mode === 'agent') {
    // Таймаут 30 минут
    const SESSION_TIMEOUT = 30 * 60 * 1000;
    if (Date.now() - session.lastActivity < SESSION_TIMEOUT) {
      session.lastActivity = Date.now();
      staticData.activeSessions = sessions;
      return [{ json: {
        type: 'agent_session',
        chat_id: chatId,
        text: text,
        question: text,
        has_photo: hasPhoto,
        photo_id: photoId,
        from: msg.from,
        message_id: msg.message_id
      } }];
    } else {
      // Сессия истекла
      delete sessions[chatId];
      staticData.activeSessions = sessions;
    }
  }

  return [{ json: {
    type: 'message',
    chat_id: chatId,
    text: text,
    has_photo: hasPhoto,
    photo_id: photoId,
    from: msg.from,
    message_id: msg.message_id
  } }];
}

return [{ json: { type: 'unknown' } }];

const prev = $('Определить тип').first().json;
const resp = $input.first().json;

let parsed = { 
  intent: 'unknown', 
  query: '', 
  query_ru: '',
  needs_confirm: true, 
  question: 'Что ты хочешь сделать?' 
};

try {
  const content = resp.choices?.[0]?.message?.content || '';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    parsed = JSON.parse(match[0]);
  }
} catch(e) {
  console.log('Parse error:', e.message);
}

return [{ json: {
  chat_id: prev.chat_id,
  text: prev.text,
  has_photo: prev.has_photo,
  photo_id: prev.photo_id,
  intent: parsed.intent || 'unknown',
  query: parsed.query || prev.text,
  query_ru: parsed.query_ru || parsed.query || prev.text,
  needs_confirm: parsed.needs_confirm !== false,
  question: parsed.question || 'Правильно ли я понял?'
} }];

const staticData = $getWorkflowStaticData('global');
const pending = staticData.pendingConfirms || {};
const sessions = staticData.activeSessions || {};
const data = $input.first().json;

const requestId = data.requestId;
const action = data.action;
const chatId = data.chat_id;

if (!requestId || !pending[requestId]) {
  return [{ json: { route: 'expired', chat_id: chatId, error: 'Запрос устарел. Попробуй снова.' } }];
}

const state = pending[requestId];
delete pending[requestId];
staticData.pendingConfirms = pending;

// Подтверждение текущего выбора
if (action === 'confirm_yes') {
  // Если подтверждают agent_chat - создаём сессию
  if (state.intent === 'agent_chat') {
    sessions[chatId] = { mode: 'agent', lastActivity: Date.now() };
    staticData.activeSessions = sessions;
  }
  return [{ json: { 
    route: 'execute',
    chat_id: chatId,
    intent: state.intent,
    query: state.query,
    question: state.originalMessage,
    originalMessage: state.originalMessage
  } }];
}

// Переключение на Pexels
if (action === 'switch_pexels') {
  delete sessions[chatId]; // Сброс сессии
  staticData.activeSessions = sessions;
  return [{ json: { 
    route: 'execute',
    chat_id: chatId,
    intent: 'pexels_search',
    query: state.query,
    originalMessage: state.originalMessage
  } }];
}

// Переключение на YouTube
if (action === 'switch_youtube') {
  delete sessions[chatId]; // Сброс сессии
  staticData.activeSessions = sessions;
  return [{ json: { 
    route: 'execute',
    chat_id: chatId,
    intent: 'youtube_search',
    query: state.query,
    originalMessage: state.originalMessage
  } }];
}

// Переключение на AI Агент - СОЗДАЁМ СЕССИЮ!
if (action === 'switch_agent') {
  sessions[chatId] = { mode: 'agent', lastActivity: Date.now() };
  staticData.activeSessions = sessions;
  return [{ json: { 
    route: 'execute',
    chat_id: chatId,
    intent: 'agent_chat',
    query: state.query,
    question: state.originalMessage,
    originalMessage: state.originalMessage
  } }];
}

// Отмена
if (action === 'confirm_no') {
  delete sessions[chatId]; // Сброс сессии
  staticData.activeSessions = sessions;
  return [{ json: { route: 'clarify', chat_id: chatId } }];
}

return [{ json: { route: 'unknown', chat_id: chatId } }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.pendingConfirms) staticData.pendingConfirms = {};

const data = $input.first().json;
const requestId = 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

staticData.pendingConfirms[requestId] = {
  intent: data.intent,
  query: data.query,           // английский
  query_ru: data.query_ru,     // русский ← ДОБАВЬ
  originalMessage: data.text,
  has_photo: data.has_photo,
  photo_id: data.photo_id,
  createdAt: new Date().toISOString()
};

// Cleanup old requests (older than 1 hour)
const oneHourAgo = Date.now() - 3600000;
for (const id of Object.keys(staticData.pendingConfirms)) {
  const req = staticData.pendingConfirms[id];
  if (new Date(req.createdAt).getTime() < oneHourAgo) {
    delete staticData.pendingConfirms[id];
  }
}

return [{ json: {
  chat_id: data.chat_id,
  question: data.question,
  requestId: requestId
} }];

const data = $input.first().json;
const intent = data.intent || 'unknown';
const query = data.query || '';
const query_ru = data.query_ru || query;
const chatId = data.chat_id;
const hasPhoto = data.has_photo || data.originalMessage?.has_photo;
const photoId = data.photo_id || data.originalMessage?.photo_id;
const text = data.text || data.originalMessage;

if (intent === 'pexels_search') {
  return [{ json: {
    route: 'pexels',
    chat_id: chatId,
    query: query,
    query_ru: query_ru
  } }];
}

if (intent === 'youtube_search' || hasPhoto) {
  return [{ json: {
    route: 'youtube',
    chat_id: chatId,
    photo_id: photoId,
    has_photo: hasPhoto,
    caption: text,
    project_hint: null
  } }];
}

if (intent === 'agent_chat') {
  return [{ json: {
    route: 'agent',
    chat_id: chatId,
    question: text,
    query_ru: query_ru
  } }];
}

return [{ json: {
  route: 'unknown',
  chat_id: chatId,
  error: 'Не понял задачу. Попробуй уточнить.'
} }];

const geminiResp = $input.first().json;

const loopData = $('Цикл: анализ превью').first().json;
const current = loopData.current || loopData;
const firstItem = $('Топ-5 кандидатов').first().json;

let analysis = { description: '', scores: {}, total: 0, verdict: '' };

try {
  let content = '';
  if (geminiResp.content && geminiResp.content.parts) {
    content = geminiResp.content.parts[0].text || '';
  } else {
    content = geminiResp.text || geminiResp.output || geminiResp.response || JSON.stringify(geminiResp);
  }

  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    analysis = JSON.parse(match[0]);
  }
} catch(e) {}

// Считаем СРЕДНЕЕ значение, не сумму!
const scoreValues = Object.values(analysis.scores || {});
const avgScore = scoreValues.length > 0 
  ? Math.round(scoreValues.reduce((a, b) => a + b, 0) / scoreValues.length)
  : 0;

return [{ json: {
  chat_id: firstItem.chat_id || loopData.chat_id,
  query: firstItem.query || loopData.query,
  query_ru: firstItem.query_ru || loopData.query_ru,
  analysis: {
    index: current.index,
    pexels_id: current.pexels_id,
    mp4_url: current.mp4_url,
    preview_url: current.preview_url,
    duration: current.duration,
    mp4_quality: current.mp4_quality,
    size_mb: current.size_mb,
    description: analysis.description || '',
    scores: analysis.scores || {},
    total: avgScore,
    verdict: analysis.verdict || ''
  }
} }];

const prev = $('Определить маршрут').first().json;
const data = $input.first().json;
const videos = data.videos || [];

if (!videos.length) {
  return [{ json: { 
    chat_id: prev.chat_id, 
    query: prev.query,
    query_ru: prev.query_ru,
    error: 'Pexels не нашёл видео по запросу' 
  }}];
}

const MAX_SIZE = 150 * 1024 * 1024;

const prepared = videos.slice(0, 10).map((v, index) => {
  const mp4Files = (v.video_files || [])
    .filter(f => f.file_type === 'video/mp4' && (f.size || 0) < MAX_SIZE)
    .sort((a, b) => (b.height || 0) - (a.height || 0));

  const bestFile = mp4Files[0];
  if (!bestFile) return null;

  const preview = v.video_pictures?.[0]?.picture || v.image;

  return {
    index: index,
    pexels_id: v.id,
    preview_url: preview,
    duration: v.duration,
    width: v.width,
    height: v.height,
    orientation: v.width < v.height ? 'vertical' : 'horizontal',
    mp4_url: bestFile.link,
    mp4_quality: `${bestFile.width}x${bestFile.height}`,
    size_mb: Math.round((bestFile.size || 0) / 1024 / 1024 * 10) / 10
  };
}).filter(v => v !== null).slice(0, 5);

if (!prepared.length) {
  return [{ json: { 
    chat_id: prev.chat_id, 
    query: prev.query,
    error: 'Не найдено подходящих MP4 файлов' 
  }}];
}

return prepared.map(candidate => ({ json: {
  chat_id: prev.chat_id,
  query: prev.query,
  query_ru: prev.query_ru,
  total_candidates: prepared.length,
  all_candidates: prepared,
  current: candidate
}}));

const items = $input.all();
const MIN_SCORE = 70; // Минимальный проходной балл (0-100)

if (!items.length) {
  return [{ json: { error: 'Нет результатов анализа' } }];
}

const first = items[0].json;
const analyses = items.map(i => i.json.analysis).filter(a => a && a.pexels_id);

if (!analyses.length) {
  return [{ json: { error: 'Нет валидных анализов' } }];
}

const sorted = analyses.sort((a, b) => {
  const aMatch = (a.verdict || '').toLowerCase().includes('подход') ? 1 : 0;
  const bMatch = (b.verdict || '').toLowerCase().includes('подход') ? 1 : 0;
  if (aMatch !== bMatch) return bMatch - aMatch;
  return (b.total || 0) - (a.total || 0);
});

const winner = sorted[0];
const bestScore = winner.total || 0;

if (bestScore < MIN_SCORE) {
  const allScores = sorted.slice(0, 3).map(a => `#${(a.index||0)+1}: ${a.total || 0}`).join(', ');
  return [{ json: {
    chat_id: first.chat_id,
    query: first.query,
    query_ru: first.query_ru,
    error: `Не нашёл достойных вариантов (лучший: ${bestScore}/100)\n\nОценки: ${allScores}\n\nПопробуй уточнить запрос.`
  } }];
}

return [{ json: {
  chat_id: first.chat_id,
  query: first.query,
  query_ru: first.query_ru,
  selected: {
    pexelsVideoId: winner.pexels_id,
    mp4Url: winner.mp4_url,
    width: parseInt(winner.mp4_quality?.split('x')[0]) || 1920,
    height: parseInt(winner.mp4_quality?.split('x')[1]) || 1080,
    duration: winner.duration,
    previewUrl: winner.preview_url,
    sizeMB: winner.size_mb
  },
  ai_score: bestScore,
  ai_sees: winner.description || '',
  ai_reason: winner.verdict || '',
  all_scores: sorted.map(a => ({ id: a.pexels_id, score: a.total, verdict: a.verdict }))
} }];

const output = $input.first().json.output || '';

// Получаем chat_id
let chatId;
try {
  chatId = $('Маршрутизация').first().json.chat_id;
} catch(e) {
  try {
    chatId = $('Тип сообщения').first().json.chat_id;
  } catch(e2) {
    chatId = null;
  }
}

// Ищем ПРЯМЫЕ ссылки на файлы (не страницы!)
// Modrinth CDN, images.unsplash.com, images.pexels.com, etc
const urlPatterns = [
  /https:\/\/cdn\.modrinth\.com\/data\/[^\s\)\]"<>]+/g,
  /https:\/\/images\.unsplash\.com\/photo-[^\s\)\]"<>?]+/g,
  /https:\/\/images\.pexels\.com\/photos\/[^\s\)\]"<>?]+/g,
  /https?:\/\/[^\s\)\]"<>]+\.(jpg|jpeg|png|gif|webp|jar|zip|mp4|mp3|pdf)[^\s\)\]"<>]*/gi
];

let urls = [];
for (const pattern of urlPatterns) {
  const matches = output.match(pattern) || [];
  urls = urls.concat(matches);
}

// Уникальные и чистим от мусора
urls = [...new Set(urls)].map(u => u.replace(/[\)\]"<>]+$/, ''));

if (urls.length === 0) {
  return [{ json: { 
    skip_download: true, 
    chat_id: chatId,
    message: output 
  } }];
}

return [{ json: {
  skip_download: false,
  chat_id: chatId,
  urls: urls,
  filenames: urls.map(u => {
    const parts = u.split('/');
    let name = parts.pop() || parts.pop();
    name = name.split('?')[0];
